const SAEC_RomType_ALL_KICK	= (SAEC_RomType_KICK | SAEC_RomType_KICKCD32 | SAEC_RomType_CD32) >>> 0;
const SAEC_RomType_ALL_EXT	= (SAEC_RomType_EXTCD32 | SAEC_RomType_EXTCDTV) >>> 0;
