	function checkromdata(crc32, size, mask) {
		for (var i = 0; i < roms.length; i++) {
			if (!notcrc32(roms[i].crc32) && roms[i].size >= size) {
				if (roms[i].type & mask) {
					if (crc32 == roms[i].crc32)
						return roms[i];
				}
			}
		}
		return null;
	}

