	this.org = function(a) {
		if (((a & 0xffff0000) >>> 0 != 0x00f00000) && ((a & 0xffff0000) >>> 0 != SAEV_AutoConf_base))
			SAEF_warn("autoconf.org() corrupt address %08X", a);
		rt_addr = a & 0xffff;
	}

	this.here = function() {
		return addr(rt_addr);
	}

