		b[0x41] = crc >> 16;
		b[0x42] = crc >>  8;
		b[0x43] = crc >>  0;

		// write header
		SAEF_ZFile_fseek(zf, 0, SEEK_SET);
		SAEF_ZFile_fwrite(b,0, 512, 1, zf);
		// write footer
