	//var cd32_shifter = [8,8];
	//var relativecount = [[0,0],[0,0],[0,0],[0,0]];

	var potgo_value = 0; //u16
	var pot_cap = [[0,0],[0,0]];
	var pot_dat = [[0,0],[0,0]]; //u8
	var pot_dat_act = [[0,0],[0,0]];
	const POTDAT_DELAY_PAL = 8;
	const POTDAT_DELAY_NTSC = 7;

