		xredcolor_s = rs;
		xgreencolor_s = gs;
		xbluecolor_s = bs;
		xredcolor_m = (((1 << rw) - 1) << xredcolor_s) >>> 0;
		xgreencolor_m = (((1 << gw) - 1) << xgreencolor_s) >>> 0;
		xbluecolor_m = (((1 << bw) - 1) << xbluecolor_s) >>> 0;
