	function putpixel(buf, bpp, x, c8, opaq) {
		if (x <= 0)
			return;

		switch (bpp) {
			case 1:
				buf[x] = c8 & 0xff;
				break;
			case 2: {
				//uae_u16 *p = (uae_u16*)buf + x; *p = (uae_u16)c8;
				buf[x] = c8 & 0xffff;
				break;
			}
			case 3: //no 24 bit yet
				break;
			case 4: {
				if (1 || opaq || SAEV_config.video.gf[0].gfx_filter == 0) {
					//uae_u32 *p = (uae_u32*)buf + x; *p = c8;
					buf[x] = c8;
				} else {
					for (var i = 0; i < 4; i++) {
						var v1 = buf[i + bpp * x];
						var v2 = (c8 >> (i * 8)) & 255;
						v1 = (v1 * 2 + v2 * 3) / 5;
						if (v1 > 255)
							v1 = 255;
						buf[i + bpp * x] = v1;
					}
				}
				break;
			}
		}
	}


