	const VBLANK_ENDLINE_NTSC = 21;

	const VBLANK_SPRITE_PAL = 25; // line when sprite DMA fetches first control words
	const VBLANK_SPRITE_NTSC = 20;
	const VBLANK_HZ_PAL = 50;
