	function I_MOVE_SR2(p) {
		if (regs.s || model == 68000) { /* This instruction is not privileged for the MC68000 and MC68008 */
			var sr = coreGetSR();
			//SAEF_log(("I_MOVE_SR2.W sr $%04x", sr));
			stEA16tab[p.ea](sr);
			coreSyncPC();
			//ccna
			return p.cyc;
		} else {
			//SAEF_log("I_MOVE_2SR PRIVILIG VIOLATION");
			//coreClrPC();
			return coreException(8);
		}
	}

