							var cyc = getEAMode(ea) == M_rdd ? [avg,1,0] : addCycs([avg,1,0], getEACycs(ea, z2));
							iTab[op] = mkI(op, "DIVS", cyc);
							iTab[op].p.Dn = Dn;
							iTab[op].p.ea = ea;
