						iTab[op].p.id = ID_BFINS;
						iTab[op].p.ea = ea;
						iTab[op].f = I_BFXXX;
						iTab[op].d = mkDiss(1, D_EA,ea, D_EXT_BITFIELD,0, 0,0);
